/**
 * Question Services
 *
 * REST API calls to fetch product and category questions
 * from the Omniguide backend. These are platform-agnostic.
 *
 * Uses normalize → validate → return pattern for the questions array.
 * Metadata fields (product_id, category_name, etc.) pass through as-is
 * for BigCommerce hooks to consume.
 */

import { API_ENDPOINTS } from '../constants.js';
import { getCurrentPage } from '../current-page.js';
import { normalizeQuestions } from '../adapters/rest/normalize.js';
import { RestQuestionsResponseSchema } from '../adapters/rest/schemas.js';
import type { DiscoveryQuestion } from '../types.js';

// =========================================
// Types
// =========================================

export interface QuestionServiceConfig {
  /** Omniguide backend base URL */
  apiBaseUrl: string;
  /** Website identifier (sent as website_code) */
  websiteId: string;
}

export interface QuestionsResponse {
  questions: DiscoveryQuestion[];
  [key: string]: unknown;
}

// =========================================
// Product Questions
// =========================================

/**
 * Fetch product questions from the Omniguide REST API.
 * Returns empty questions array on 404 (product not found / no questions).
 * Questions are normalized and validated; metadata passes through as-is.
 */
export async function fetchProductQuestions(
  config: QuestionServiceConfig,
  sku: string,
): Promise<QuestionsResponse> {
  if (!sku) {
    return { questions: [] };
  }

  const currentPage = getCurrentPage();

  const params = new URLSearchParams({
    website_code: config.websiteId,
    sku,
    current_page: currentPage,
  });

  const url = `${config.apiBaseUrl}${API_ENDPOINTS.PRODUCT_QUESTIONS}?${params}`;

  const response = await fetch(url, {
    method: 'GET',
    headers: { 'Content-Type': 'application/json' },
  });

  if (!response.ok) {
    if (response.status === 404) {
      return { questions: [] };
    }
    throw new Error(`Failed to fetch product questions: ${response.statusText}`);
  }

  const raw = await response.json();
  const normalized = normalizeQuestions(raw);
  const validated = RestQuestionsResponseSchema.safeParse(normalized);

  return {
    ...raw,
    questions: validated.success ? validated.data : [],
  };
}

// =========================================
// Category Questions
// =========================================

/**
 * Fetch category questions from the Omniguide REST API.
 * Returns empty questions array on 404 (category not found / no questions).
 * Questions are normalized and validated; metadata passes through as-is.
 */
export async function fetchCategoryQuestions(
  config: QuestionServiceConfig,
  categoryUrl?: string,
): Promise<QuestionsResponse> {
  const resolvedUrl = categoryUrl ?? (typeof window !== 'undefined' ? window.location.pathname : '');
  const currentPage = getCurrentPage();

  const params = new URLSearchParams({
    website_code: config.websiteId,
    category_url: resolvedUrl,
    current_page: currentPage,
  });

  const url = `${config.apiBaseUrl}${API_ENDPOINTS.CATEGORY_QUESTIONS}?${params}`;

  const response = await fetch(url, {
    method: 'GET',
    headers: { 'Content-Type': 'application/json' },
  });

  if (!response.ok) {
    if (response.status === 404) {
      return { questions: [] };
    }
    throw new Error(`Failed to fetch category questions: ${response.statusText}`);
  }

  const raw = await response.json();
  const normalized = normalizeQuestions(raw);
  const validated = RestQuestionsResponseSchema.safeParse(normalized);

  return {
    ...raw,
    questions: validated.success ? validated.data : [],
  };
}
